// djb2-based hash (pure JS; no platform crypto needed)
function simpleHash(str) {
  let h = 5381;
  for (let i = 0; i < str.length; i++) h = ((h << 5) + h) ^ str.charCodeAt(i);
  const u = (h >>> 0).toString(16).padStart(8,'0');
  const l = ((h * 1000003 | 0) >>> 0).toString(16).padStart(8,'0');
  return (u + l).padStart(64,'0');
}

function invalid(message) {
  const err = new Error('Invalid Odoo request: ' + message);
  err.statusCode = 400;
  return err;
}

function parseJsonArray(value, fieldName) {
  let parsed = value;
  if (typeof value === 'string') {
    try {
      parsed = JSON.parse(value);
    } catch (e) {
      throw invalid(fieldName + ' must be valid JSON');
    }
  }
  if (!Array.isArray(parsed)) throw invalid(fieldName + ' must be an array');
  return parsed;
}

// Copy only scalars and arrays-of-scalars into flat metadata. search_read
// returns scalars, many2one as [id, name], and x2many as [ids]; never nested
// objects. This keeps the DecisionCenter EvidenceObject flat-metadata contract.
function flattenRecord(record) {
  const out = {};
  for (const k of Object.keys(record)) {
    if (k === 'id') continue;
    const v = record[k];
    if (v === null || v === undefined) { out['f_' + k] = null; continue; }
    const t = typeof v;
    if (t === 'string' || t === 'number' || t === 'boolean') {
      out['f_' + k] = v;
    } else if (Array.isArray(v)) {
      const scalarOnly = v.every(e => e === null || ['string','number','boolean'].includes(typeof e));
      if (scalarOnly) out['f_' + k] = v;
    }
  }
  return out;
}

try {
  const raw = $('Receive Request').first().json.body || $('Receive Request').first().json;
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) throw invalid('JSON object body is required');
  if (typeof raw.model !== 'string' || raw.model.trim() === '') throw invalid('model is required');
  if (raw.domain === undefined) throw invalid('domain is required');

  // operation: 'read' (default, back-compat) returns evidence; 'count' returns
  // an exact search_count total. Adding these is additive — callers that send
  // neither operation nor offset get the original read-first-page behaviour.
  const operation = (raw.operation === undefined || raw.operation === null)
    ? 'read' : String(raw.operation).trim().toLowerCase();
  if (operation !== 'read' && operation !== 'count') throw invalid("operation must be 'read' or 'count'");
  if (operation === 'read' && raw.fields === undefined) throw invalid('fields is required');

  const odooUrl = ($env.ODOO_URL || '').replace(/\/$/, '');
  const db = $env.ODOO_DATABASE;
  const user = $env.ODOO_USERNAME;
  const apiKey = $env.ODOO_API_KEY;
  if (!odooUrl || !db || !user || !apiKey) throw new Error('Odoo runtime credentials are not configured');

  const model = raw.model.trim();
  const domain = parseJsonArray(raw.domain, 'domain');
  const projCode = raw.project_code || null;

  const authResp = await this.helpers.httpRequest({
    method: 'POST', url: odooUrl + '/jsonrpc',
    headers: {'Content-Type': 'application/json'},
    body: {jsonrpc:'2.0',method:'call',id:1,
           params:{service:'common',method:'authenticate',args:[db,user,apiKey,{}]}},
  });
  const uid = authResp.result;
  if (!uid) throw new Error('Odoo auth failed: ' + JSON.stringify(authResp.error));

  // --- COUNT: exact total via search_count; read-only, project-scoped domain ---
  if (operation === 'count') {
    const countResp = await this.helpers.httpRequest({
      method: 'POST', url: odooUrl + '/jsonrpc',
      headers: {'Content-Type': 'application/json'},
      body: {jsonrpc:'2.0',method:'call',id:3,
             params:{service:'object',method:'execute_kw',
               args:[db,uid,apiKey,model,'search_count',[domain]]}},
    });
    if (countResp.error) throw new Error('Odoo search_count failed: ' + JSON.stringify(countResp.error));
    const total = Number.isInteger(countResp.result) ? countResp.result
      : (Array.isArray(countResp.result) ? countResp.result.length : 0);
    return [{ json: { count: total, model: model, project_code: projCode,
                      meta: { operation: 'count' } } }];
  }

  // --- READ: bounded, paged search_read (offset honoured for safe sampling) ---
  const fields = parseJsonArray(raw.fields, 'fields');
  const requestedLimit = Number(raw.limit ?? 100);
  if (!Number.isInteger(requestedLimit) || requestedLimit < 1 || requestedLimit > 100) throw invalid('limit must be an integer between 1 and 100');
  let offset = Number(raw.offset ?? 0);
  if (!Number.isInteger(offset) || offset < 0) throw invalid('offset must be a non-negative integer');

  const execResp = await this.helpers.httpRequest({
    method: 'POST', url: odooUrl + '/jsonrpc',
    headers: {'Content-Type': 'application/json'},
    body: {jsonrpc:'2.0',method:'call',id:2,
           params:{service:'object',method:'execute_kw',
             args:[db,uid,apiKey,model,'search_read',
                   [domain],{fields:fields.length?fields:['name','id'],limit:requestedLimit,offset:offset}]}},
  });
  const records = Array.isArray(execResp.result) ? execResp.result : [];

  const evidence = records.map((record, index) => {
    const recordId = record.id !== undefined ? String(record.id) : String(index);
    const timestamp = record.write_date || record.create_date || record.date || null;
    const valueKeys = Object.keys(record).filter(k => !['id','create_date','write_date','__last_update'].includes(k));
    const valuePreview = valueKeys.slice(0,5).map(k => k + ': ' + String(record[k] ?? '')).join('; ');
    const baseMeta = {
      model: model,
      record_id: record.id !== undefined ? record.id : null,
      currency: record.currency_id ? record.currency_id[1] : (record.currency || null)
    };
    return {
      evidence_id: 'odoo-' + model.replace(/\./g, '-') + '-' + recordId,
      source_type: 'odoo',
      source_uri: odooUrl + '/web#id=' + recordId + '&model=' + encodeURIComponent(model),
      title: record.name || record.display_name || (model + ' #' + recordId),
      project_code: projCode,
      contract_no: raw.contract_no || null,
      revision: null,
      timestamp: timestamp,
      excerpt: valuePreview.substring(0, 1000),
      hash_sha256: simpleHash(model + '-' + recordId + '-' + (timestamp || '')),
      confidence: 'high',
      tags: ['odoo', model],
      metadata: Object.assign(baseMeta, flattenRecord(record))
    };
  });
  return [{ json: { evidence: evidence,
                    meta: { operation: 'read', offset: offset, limit: requestedLimit, returned: evidence.length } } }];
} catch(e) {
  const statusCode = e.statusCode || 502;
  return [{ json: { evidence: [], error: e.message, statusCode } }];
}
